        os.makedirs(output_dir, exist_ok=True)
        
        # Build the LibreOffice command
        cmd = [
            'libreoffice',
            '--headless',
            '--convert-to',
            format_type,
            '--outdir',
            output_dir,
            input_path
        ]
        
